import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';
import 'chat_screen.dart';

class MatchesScreen extends StatefulWidget {
  const MatchesScreen({super.key});

  @override
  State<MatchesScreen> createState() => _MatchesScreenState();
}

class _MatchesScreenState extends State<MatchesScreen> {
  static const _bg = Color(0xFF0E0E0E);
  static const _baseUrl = 'http://10.0.2.2:8000';
  static const _streamApiKey = '[REDACTED_STREAM_KEY]';

  bool _isLoading = true;
  String? _error;
  List<Map<String, dynamic>> _matches = [];
  String? _streamToken;
  String? _currentUsername;

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<String?> _getToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token');
  }

  Future<void> _load() async {
    setState(() { _isLoading = true; _error = null; });
    try {
      final prefs = await SharedPreferences.getInstance();
      final jwtToken = prefs.getString('jwt_token');
      final username = prefs.getString('username');

      if (jwtToken == null) {
        setState(() { _error = 'Not logged in'; _isLoading = false; });
        return;
      }

      final headers = {'Authorization': 'Bearer $jwtToken'};

      final results = await Future.wait([
        http.get(Uri.parse('$_baseUrl/api/matches'), headers: headers),
        http.get(Uri.parse('$_baseUrl/api/stream-token'), headers: headers),
      ]);

      final matchesRes = results[0];
      final streamRes = results[1];

      if (matchesRes.statusCode != 200) {
        setState(() { _error = 'Failed to load matches (${matchesRes.statusCode})'; _isLoading = false; });
        return;
      }

      final matchesData = jsonDecode(matchesRes.body) as Map<String, dynamic>;
      final matches = (matchesData['matches'] as List<dynamic>? ?? []).cast<Map<String, dynamic>>();

      String? streamToken;
      if (streamRes.statusCode == 200) {
        final streamData = jsonDecode(streamRes.body) as Map<String, dynamic>;
        streamToken = streamData['token'] as String?;
      }

      setState(() {
        _matches = matches;
        _streamToken = streamToken;
        _currentUsername = username;
        _isLoading = false;
      });
    } catch (e) {
      setState(() { _error = 'Error: $e'; _isLoading = false; });
    }
  }

  void _openChat(Map<String, dynamic> match) {
    if (_streamToken == null || _currentUsername == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Chat unavailable — could not get Stream token')),
      );
      return;
    }
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => ChatScreen(
          matchUsername: match['username'] as String,
          currentUsername: _currentUsername!,
          streamToken: _streamToken!,
          apiKey: _streamApiKey,
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        elevation: 0,
        centerTitle: true,
        title: const Column(
          children: [
            Text(
              'MATCHES',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.bold,
                fontSize: 16,
                letterSpacing: 1.2,
              ),
            ),
            Text(
              'People who like each other',
              style: TextStyle(color: Colors.white38, fontSize: 11),
            ),
          ],
        ),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh, color: Colors.white54),
            onPressed: _load,
          ),
        ],
      ),
      body: _buildBody(),
    );
  }

  Widget _buildBody() {
    if (_isLoading) {
      return const Center(child: CircularProgressIndicator(color: Colors.greenAccent));
    }
    if (_error != null) {
      return Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text(_error!, style: const TextStyle(color: Colors.redAccent)),
            const SizedBox(height: 16),
            TextButton(onPressed: _load, child: const Text('Retry')),
          ],
        ),
      );
    }
    if (_matches.isEmpty) {
      return RefreshIndicator(
        onRefresh: _load,
        color: Colors.greenAccent,
        child: ListView(
          children: const [
            SizedBox(height: 200),
            Center(
              child: Column(
                children: [
                  Icon(Icons.favorite, size: 64, color: Colors.greenAccent),
                  SizedBox(height: 16),
                  Text('No matches yet', style: TextStyle(color: Colors.white70, fontSize: 16)),
                  SizedBox(height: 8),
                  Text('Keep liking people!', style: TextStyle(color: Colors.white38, fontSize: 13)),
                ],
              ),
            ),
          ],
        ),
      );
    }

    return RefreshIndicator(
      onRefresh: _load,
      color: Colors.greenAccent,
      child: ListView.separated(
        padding: const EdgeInsets.only(top: 8, bottom: 80),
        itemCount: _matches.length,
        separatorBuilder: (_, __) => const Divider(height: 1, color: Colors.white10),
        itemBuilder: (context, index) {
          final match = _matches[index];
          final int userId = match['id'] as int? ?? 0;
          final String username = match['username'] as String? ?? '';
          final int? age = match['age'] as int?;
          final String? sex = match['sex'] as String?;
          final String photoUrl = '$_baseUrl/api/users/$userId/photo';

          return GestureDetector(
            onTap: () => _openChat(match),
            child: Container(
              color: _bg,
              padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
              child: Row(
                children: [
                  CircleAvatar(
                    radius: 24,
                    backgroundColor: Colors.white12,
                    child: ClipOval(
                      child: Image.network(
                        photoUrl,
                        width: 48,
                        height: 48,
                        fit: BoxFit.cover,
                        errorBuilder: (_, __, ___) => Text(
                          username.isNotEmpty ? username[0].toUpperCase() : '?',
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 18,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 14),
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          username,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 16,
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                        if (age != null || sex != null)
                          Text(
                            [if (age != null) '$age', if (sex != null) sex!].join(' · '),
                            style: const TextStyle(color: Colors.white38, fontSize: 12),
                          ),
                      ],
                    ),
                  ),
                  IconButton(
                    onPressed: () => _openChat(match),
                    icon: const Icon(Icons.message_rounded, color: Colors.greenAccent, size: 26),
                  ),
                ],
              ),
            ),
          );
        },
      ),
    );
  }
}

