import 'package:flutter/material.dart';
import 'package:curved_navigation_bar/curved_navigation_bar.dart';
import 'users_screen.dart';
import 'who_i_like_screen.dart';
import 'who_likes_me_screen.dart';
import 'matches_screen.dart';
import 'settings_screen.dart';

class MainScreen extends StatefulWidget {
  const MainScreen({super.key});

  @override
  State<MainScreen> createState() => _MainScreenState();
}

class _MainScreenState extends State<MainScreen> {
  int _currentIndex = 0;

  static const _navBackground = Color(0xFF1E1E2E);

  List<Widget> get _screens => [
        const UsersScreen(),                     // 0 – Search
        WhoILikeScreen(onSwitchTab: _switchTab), // 1 – Who I Like
        const WhoLikesMeScreen(),                // 2 – Who Likes Me
        const MatchesScreen(),                   // 3 – Matches
      ];

  void _switchTab(int index) {
    setState(() => _currentIndex = index);
  }

  final List<Widget> _navItems = const [
    Icon(Icons.explore,        color: Colors.white, size: 26), // 0 Search
    Icon(Icons.arrow_forward,  color: Colors.white, size: 26), // 1 Who I Like
    Icon(Icons.arrow_back,     color: Colors.white, size: 26), // 2 Who Likes Me
    Icon(Icons.favorite,       color: Colors.white, size: 26), // 3 Matches
  ];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      extendBody: true,
      body: IndexedStack(
        index: _currentIndex,
        children: _screens,
      ),
      bottomNavigationBar: CurvedNavigationBar(
        index: _currentIndex,
        height: 60,
        color: _navBackground,
        backgroundColor: Colors.transparent,
        buttonBackgroundColor: Colors.blueAccent,
        animationDuration: const Duration(milliseconds: 300),
        animationCurve: Curves.easeInOut,
        items: _navItems,
        onTap: (index) => setState(() => _currentIndex = index),
      ),
    );
  }
}

